import{_ as a,o as r,c as t,a2 as o}from"./chunks/framework.BWuWLRhz.js";const i="/images/20-things-i-learned-while-i-was-in/Map-1.png",n="/images/20-things-i-learned-while-i-was-in/Map-2.png",l="/images/20-things-i-learned-while-i-was-in/Map-3.png",p="/images/20-things-i-learned-while-i-was-in/Map-4.png",s="/images/20-things-i-learned-while-i-was-in/Map-MAP.png",h="/images/20-things-i-learned-while-i-was-in/Map-5.png",g="/images/20-things-i-learned-while-i-was-in/Map-6.png",w="/images/20-things-i-learned-while-i-was-in/kim-il-sung.jpg",m="/images/20-things-i-learned-while-i-was-in/kim_jong_il__s_smile_by_shitalloverhumanity-d5d4mw9.jpg",c="/images/20-things-i-learned-while-i-was-in/517f07d53ed50.image.jpg",b="/images/20-things-i-learned-while-i-was-in/kim-n-kim-kis-sq-300x192.jpg",_="/images/20-things-i-learned-while-i-was-in/Elephant.png",u="/images/20-things-i-learned-while-i-was-in/Screen-Shot-2013-09-27-at-1.48.05-AM.png",f="/images/20-things-i-learned-while-i-was-in/FB-Thumbnail.png",d="/images/20-things-i-learned-while-i-was-in/KJU-Birth.png",k="/images/20-things-i-learned-while-i-was-in/KJU-Birth-2.png",A="/images/20-things-i-learned-while-i-was-in/KJU-Birth-4.png",y="/images/20-things-i-learned-while-i-was-in/IMG_0688.jpg",q="/images/20-things-i-learned-while-i-was-in/IMG_2060.jpg",I="/images/20-things-i-learned-while-i-was-in/IMG_0540.jpg",P="/images/20-things-i-learned-while-i-was-in/IMG_0839.jpg",x="/images/20-things-i-learned-while-i-was-in/170387569.jpg",j="/images/20-things-i-learned-while-i-was-in/Finder.png",N="/images/20-things-i-learned-while-i-was-in/China.png",M="/images/20-things-i-learned-while-i-was-in/pinit_fg_en_rect_gray_20.png",B=JSON.parse('{"title":"20 Things I Learned While I Was in North Korea","description":"","frontmatter":{"title":"20 Things I Learned While I Was in North Korea","titleZh":"我在朝鲜学到的20件事","date":"2013-09-27T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2013/09/20-things-i-learned-while-i-was-in.html","slug":"20-things-i-learned-while-i-was-in"},"headers":[],"relativePath":"posts/20-things-i-learned-while-i-was-in.md","filePath":"posts/20-things-i-learned-while-i-was-in.md","lastUpdated":1782886257000}'),K={name:"posts/20-things-i-learned-while-i-was-in.md"};function v(G,e,U,T,W,S){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="我在朝鲜学到的20件事-·-20-things-i-learned-while-i-was-in-north-korea" tabindex="-1">我在朝鲜学到的20件事 · 20 Things I Learned While I Was in North Korea <a class="header-anchor" href="#我在朝鲜学到的20件事-·-20-things-i-learned-while-i-was-in-north-korea" aria-label="Permalink to &quot;我在朝鲜学到的20件事 · 20 Things I Learned While I Was in North Korea&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2013/09/20-things-i-learned-while-i-was-in.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2013/09/20-things-i-learned-while-i-was-in.html</a> · 2013-09-27</p></blockquote><p>好吧,那真是一段诡异的经历。</p><p>我在朝鲜只待了五天,但这五天已经足够让我确认——朝鲜跟我一直以为的一样,怪到骨子里。</p><p>如果你把斯大林时代的苏联跟一个中国古代帝国合并起来,再混入《楚门的世界》(The Truman Show),然后再给整个东西加一层大屠杀氛围,你就得到了今天的朝鲜。</p><p>它是最极端的那种独裁国家,是斯大林或毛泽东都想象不到的个人崇拜巅峰,是一个对世界封闭得不能再封闭、秘密得不能再秘密的国家,把外部世界和自己的人民彼此完全蒙在鼓里——一个货真价实的隐士王国。</p><p>那么问题来了:「为什么一个美国游客会被允许进入这个国家?」</p><p>请允许我图解一下我认为自己被放进去的原因:</p><h2 id="高层政府会议" tabindex="-1"><strong>高层政府会议</strong> <a class="header-anchor" href="#高层政府会议" aria-label="Permalink to &quot;**高层政府会议**&quot;">​</a></h2><p><a href="https://waitbutwhy.com/" target="_blank" rel="noreferrer"><img src="'+i+'" alt=""></a></p><p><a href="https://waitbutwhy.com/" target="_blank" rel="noreferrer"><img src="'+n+'" alt=""></a></p><p><a href="https://waitbutwhy.com/" target="_blank" rel="noreferrer"><img src="'+l+'" alt=""></a></p><p><a href="https://waitbutwhy.com/" target="_blank" rel="noreferrer"><img src="'+p+'" alt=""></a></p><p><a href="https://waitbutwhy.com/" target="_blank" rel="noreferrer"><img src="'+s+'" alt=""></a></p><p><a href="https://waitbutwhy.com/" target="_blank" rel="noreferrer"><img src="'+h+'" alt=""></a></p><p><a href="https://waitbutwhy.com/" target="_blank" rel="noreferrer"><img src="'+g+'" alt=""></a></p><p>就这样,我获准进入了,跟一小群其他西方人一起,全程(真的是全程)由三名朝鲜导游陪同。我在那儿的经历跟上面画的路线感觉很像——我们看了平壤和另外几个地方,而我们一路上目光所及的朝鲜人,大概是这个国家里日子过得最好的那批人。</p><p>在我讲学到了什么之前,我想先跟正在读这篇文章的朝鲜政府工作人员打个招呼。在朝鲜,只有最高级别的官员才有权访问互联网,我了解到其中一个人的工作就是在网上搜刮任何跟朝鲜有关的内容、盯着外国媒体在说什么。所以你好啊,而且哈哈你抓不到我了,因为我已经回家了,现在我可以说所有那些我在你们国家不被允许说的话。</p><p>好了,既然我已经把自己咒到必然被暗杀了,那就开始吧——</p><h2 id="我在朝鲜时学到的-20-件事" tabindex="-1"><strong>我在朝鲜时学到的 20 件事</strong> <a class="header-anchor" href="#我在朝鲜时学到的-20-件事" aria-label="Permalink to &quot;**我在朝鲜时学到的 20 件事**&quot;">​</a></h2><h2 id="" tabindex="-1">** <a class="header-anchor" href="#" aria-label="Permalink to &quot;**&quot;">​</a></h2><ol><li>领导人在那儿可真他妈是个大事。**</li></ol><p>这么说都还不够劲。他们是唯一的事。这就是三巨头:</p><p><strong>1. 金日成 (Kim Il Sung,1912 – 1994)</strong></p><p><a href="https://2.bp.blogspot.com/-Ml_oE7adQMQ/UkVqH57GBlI/AAAAAAAAACw/5iYIlh2NH98/s1600/kim-il-sung.jpg" target="_blank" rel="noreferrer"><img src="'+w+'" alt=""></a></p><p>他是他们的乔治·华盛顿加斯大林加耶稣加圣诞老人的合体,全都浓缩在一个圆滚滚的、已经死掉的韩国男人身上。他是永恒的主席——之所以永恒,是因为他让这个职位在未来永久废除,这样就再也没人能当主席了。他们还几乎完全编造了一整套关于他那些从未真正达成的传奇功绩的故事。</p><p>据估计,朝鲜境内有大约 34000 尊金日成的雕像,凡是能命名的东西都以他的名字命名(如果他们今天才建国,这国家大概会叫「金日成乐园」),每个成年人被要求每天在衬衫上别一枚印着他脸的徽章,所有学生的学习中都有很大一部分用来背诵他的讲话、学习他的成就,他的生日是全国最盛大的节日。他们连年份都改了——朝鲜现在不是 2013 年,而是主体 101 年(金日成出生后第 101 年)。</p><p>作为游客,我们被告知只能称他为「金日成主席」。</p><p><strong>2. 金正日 (1941 – 2011)</strong></p><p><a href="https://2.bp.blogspot.com/-iaqF9vNvNQY/UkVqICYonoI/AAAAAAAAADE/im4HxC4FcA4/s320/kim_jong_il__s_smile_by_shitalloverhumanity-d5d4mw9.jpg" target="_blank" rel="noreferrer"><img src="'+m+'" alt=""></a></p><p>金日成的儿子,也是过去十年里我们大家都熟悉的那个混蛋。朝鲜说他出生在朝鲜一座神圣的山顶(实际上他生于苏联),说他的出生让冬天变成了春天(其实还是冬天)。他也是个了不得的人物,不过分量大概只有他爹的三分之一。有些外人质疑,朝鲜人到底是真的痴迷金正日,还是只是害怕表现得不痴迷。</p><p>我们被告知只能称他为「金正日将军」。</p><p><strong>3. 金正恩 (1983 或 1984 – )</strong></p><p><a href="https://4.bp.blogspot.com/-mE2gYwCvouQ/UkVqHxXsM2I/AAAAAAAAAC4/PFHpf5sGBb0/s320/517f07d53ed50.image.jpg" target="_blank" rel="noreferrer"><img src="'+c+'" alt=""></a></p><p>尽管现在他是最高领导人,但金正日的这个儿子接班得比所有人预期的都要早——2011 年金正日突然去世(不像金正日本人,在接班之前已经被培养了几十年)——而且虽然朝鲜的宣传机器很擅长描绘前两代金氏的传奇成就,却没人真的搞得清金正恩到底成就了什么。部分原因是老百姓直到最近才听说过金正恩——他有两个哥哥,原本应该由其中一个接班,结果一个太女性化(也就是可能是同性恋),另一个用多米尼加护照偷偷混进迪士尼乐园被抓了,俩人都没戏了,才轮到他。我在朝鲜的感受是,大家对金正恩其实并没有太多发自内心的英雄崇拜。</p><p>不过这也没妨碍他们要求我们叫他「金正恩元帅」。</p><p>而且你在这个国家走到哪儿——无论哪儿——都能看到这个:</p><p><a href="https://3.bp.blogspot.com/-uKYCGQ1FUD0/UkVqH7Tg2gI/AAAAAAAAAC0/trfAz8cj6kE/s400/kim-n-kim-kis-sq-300x192.jpg" target="_blank" rel="noreferrer"><img src="'+b+'" alt=""></a></p><p>我见到这俩哥们儿的次数多到最后觉得完全正常了,脑子里开始把他俩称为「兄弟俩」。他们的双人肖像不仅出现在每一个可能的公共场所,而且<em>要求</em>挂在这个国家每一户人家的墙上,政府还会随机上门抽查。每个家庭还会被发一条特殊的毛巾,这条毛巾<em>唯一</em>允许的用途就是每天早上把肖像擦干净。正常国家。</p><p>关于领导人的一堆规矩也同样适用于访客。当你走到其中一位兄弟的雕像前,必须鞠躬。手必须放在身侧,不能背在身后。给雕像拍照时,你<em>必须</em>把整个身体拍进去——切掉任何一部分都是不允许的。如果你手上有一份印着领导人的报纸或其他纸张,不能折叠,也不能扔掉。正常国家。</p><p>毫不意外,朝鲜在世界<a href="https://en.wikipedia.org/wiki/Democracy_Index" target="_blank" rel="noreferrer">民主指数 (Democracy Index)</a>排名中垫底。</p><h2 id="-1" tabindex="-1">** <a class="header-anchor" href="#-1" aria-label="Permalink to &quot;**&quot;">​</a></h2><p>2)所有人无时无刻不在对所有事撒谎。**</p><p><a href="https://waitbutwhy.com/" target="_blank" rel="noreferrer"><img src="'+_+'" alt=""></a></p><p>政府对外部世界撒谎。政府对人民撒谎。媒体对人民撒谎。人民彼此撒谎。导游对游客撒谎。谎撒得那叫一个惨烈。</p><p>谎言的范围从大事——政府反复灌输美国正准备攻打朝鲜的信息,媒体把韩国描绘成一个饱受苦难、被美国占领的国家,领导人在演讲中说朝鲜是全世界羡慕的对象,生活质量世界第一——到小事——我们在某处遇到了一名士兵,被告知他是上校,他走后,和我一起参团的一位退役陆军少校告诉我他研究过朝鲜军服,那个士兵其实是上尉。</p><p>事实在朝鲜这个等式里不是关键要素。</p><p>这真的会把作为访客的你搞得脑子一团浆糊。我时常发现自己陷入这种令人费解的境地,试图搞清楚一个满嘴谎言的朝鲜人到底知不知情。她心里想的是「我知道这是假的,你知道这是假的,但我住在这儿所以我得配合演戏」?还是她已经被彻底洗脑,以为自己在跟我说真话?根本没法分辨。互动过程中,我时常在想:「你是《楚门的世界》里的演员、以为我是楚门?还是你是楚门、而我是那些演员之一?」街上那些孩子是不是就是在演戏给我看?这些当中有任何东西是真的吗?我是真的吗?</p><h2 id="-2" tabindex="-1">** <a class="header-anchor" href="#-2" aria-label="Permalink to &quot;**&quot;">​</a></h2><p>3)大多数来朝鲜的游客在平壤期间被强制住在同一家酒店。**</p><p><a href="https://en.wikipedia.org/wiki/Yanggakdo_International_Hotel" target="_blank" rel="noreferrer">就是这里</a>。</p><p>你知道他们为什么把所有游客都塞在这儿吗?因为它坐落在城市正中央的一座岛上——</p><p><a href="https://2.bp.blogspot.com/-nfZsJEzVjEo/UkVs7yax_BI/AAAAAAAAAEU/_Agq4_thbmg/s640/Screen+Shot+2013-09-27+at+1.48.05+AM.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt=""></a></p><p>政府对游客最大的恐惧就是他们某个时刻溜出去,偷拍不该看到的东西,所以这个岛上的位置(酒店周围还有守卫)简直完美。白天我们从未离开过导游的视线,并且被告知无论如何都不能在夜里离开酒店。</p><p>即便全国其他地方和平壤的大部分区域都没有电、暖气或空调,羊角岛酒店始终灯火通明、温度宜人——这全都是给游客展示一个特定国家形象的计划的一部分。</p><h2 id="-3" tabindex="-1">** <a class="header-anchor" href="#-3" aria-label="Permalink to &quot;**&quot;">​</a></h2><ol start="4"><li>宣传无处不在,真的无处不在。**</li></ol><p><a href="https://4.bp.blogspot.com/-yCbiSxp_eoY/UoAYx6HAhrI/AAAAAAAAGMg/q2l_S22fKmI/s400/FB+Thumbnail.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt=""></a></p><p>从令人<a href="https://waitbutwhy.com/wp-content/uploads/2013/09/NK-01.jpg" target="_blank" rel="noreferrer">窒息</a><a href="https://waitbutwhy.com/wp-content/uploads/2013/09/NK-02.jpg" target="_blank" rel="noreferrer">数量</a><a href="https://waitbutwhy.com/wp-content/uploads/2013/09/NK-03.jpg" target="_blank" rel="noreferrer">的</a> <a href="https://waitbutwhy.com/wp-content/uploads/2013/09/NK-04.jpg" target="_blank" rel="noreferrer">广告牌</a><a href="https://waitbutwhy.com/wp-content/uploads/2013/09/NK-05.jpg" target="_blank" rel="noreferrer">和</a><a href="https://waitbutwhy.com/wp-content/uploads/2013/09/NK-06.jpg" target="_blank" rel="noreferrer">壁画</a>,到<a href="https://waitbutwhy.com/wp-content/uploads/2013/09/NK-07.jpg" target="_blank" rel="noreferrer">明信片</a>、<a href="https://waitbutwhy.com/wp-content/uploads/2013/09/NK-08.jpg" target="_blank" rel="noreferrer">小册子</a>和<a href="https://waitbutwhy.com/wp-content/uploads/2013/09/NK-09.jpg" target="_blank" rel="noreferrer">报纸</a>,再到<a href="https://waitbutwhy.com/wp-content/uploads/2013/09/NK-11.jpg" target="_blank" rel="noreferrer">电视上</a><a href="https://youtu.be/vKC8t-FKAUE" target="_blank" rel="noreferrer">的一切</a><a href="https://waitbutwhy.com/wp-content/uploads/2013/09/NK-10.jpg" target="_blank" rel="noreferrer">节目</a>,朝鲜人民被迫全天候生活在朝鲜自豪感的空气里、呼吸着它。甚至还有一个令人毛骨悚然的宣传乐队——牡丹峰乐队,成员全部由金正恩亲自挑选。<a href="https://www.youtube.com/watch?v=Yej5iuy_xT4" target="_blank" rel="noreferrer">这个视频</a>在我们进出朝鲜的航班上、以及我们去过的几乎每一家餐厅里都从头到尾播放了一遍,后来一直阴魂不散地缠绕着我的睡眠。戈培尔跟金家父子相比根本不值一提。</p><p>我看到的宣传分为四类:1)领袖及其伟大之处,尤其是金日成;2)朝鲜军队及其威力的图像;3)对美国和韩国的负面描绘;以及 4)朝鲜人民生活得欢乐幸福、阳光灿烂的图像。</p><h2 id="-4" tabindex="-1">** <a class="header-anchor" href="#-4" aria-label="Permalink to &quot;**&quot;">​</a></h2><ol start="5"><li>导游们显然不觉得当着我的面把美国人称作「美帝国主义者」有什么尴尬的。**</li></ol><p>上一条里那张明信片只是冰山一角。如果说朝鲜叙事的一半是「金日成是伟大的人」,那另一半就是「美帝国主义挑起了朝鲜战争并输掉了战争,从那以后他们就一直想把我们统统杀掉、强奸掉、把国家夺走,但我们伟大的军队不会允许这种事发生」。</p><p>朝鲜政府 <em>非常</em> 热衷于 <a href="https://waitbutwhy.com/wp-content/uploads/2013/09/NK-12.jpg" target="_blank" rel="noreferrer">反美情绪</a>——很大程度上是因为他们发现了一种办法,可以把自己所有的问题基本都甩锅给美国,并利用对美国的虚假恐惧来为自己辩解——一个只有宾夕法尼亚州大小的贫穷国家,却拥有世界第四大规模的军队(更别提在核武器技术上花掉的那笔天文数字般的钱)。</p><p>看看这位导游翻译士兵描述美国发动进攻时可能遭遇什么下场的画面:</p><p>再看看这段在「普韦布洛号 (USS Pueblo)」甲板上放给我们看的反美视频——这是一艘 1968 年被朝鲜俘获的美国海军舰船(他说「人民」的方式也挺搞笑的):</p><h2 id="_6-把朝鲜叫作「朝鲜」是不礼貌的。" tabindex="-1"><strong>6) 把朝鲜叫作「朝鲜」是不礼貌的。</strong> <a class="header-anchor" href="#_6-把朝鲜叫作「朝鲜」是不礼貌的。" aria-label="Permalink to &quot;**6) 把朝鲜叫作「朝鲜」是不礼貌的。**&quot;">​</a></h2><p>正确的叫法是「朝鲜(Korea,即整个朝鲜半岛)」。所有关于这个国家的 <a href="https://waitbutwhy.com/wp-content/uploads/2013/09/NK-13.jpg" target="_blank" rel="noreferrer">图片</a> 都画的是整个半岛,也就是今天的朝鲜和韩国加起来。在他们看来,他们是自豪的朝鲜人,生活在朝鲜,而半岛的南半部很不幸目前被美帝国主义者占领着。</p><h2 id="_7-金正恩的确切出生年份-不是你在这个国家应该试图打听的话题。" tabindex="-1"><strong>7) 金正恩的确切出生年份,不是你在这个国家应该试图打听的话题。</strong> <a class="header-anchor" href="#_7-金正恩的确切出生年份-不是你在这个国家应该试图打听的话题。" aria-label="Permalink to &quot;**7) 金正恩的确切出生年份,不是你在这个国家应该试图打听的话题。**&quot;">​</a></h2><p><a href="https://waitbutwhy.com/" target="_blank" rel="noreferrer"><img src="'+d+'" alt=""></a></p><p><a href="https://waitbutwhy.com/" target="_blank" rel="noreferrer"><img src="'+k+'" alt=""></a></p><p><a href="https://waitbutwhy.com/" target="_blank" rel="noreferrer"><img src="'+A+'" alt=""></a></p><p>这是因为确切的日期其实并没有人真正知道,而这件事显然让他们很不爽。</p><h2 id="-5" tabindex="-1">** <a class="header-anchor" href="#-5" aria-label="Permalink to &quot;**&quot;">​</a></h2><ol start="8"><li>同一个地方可以又高端又破烂。**</li></ol><p>朝鲜专门盛产「同时又高端又破烂的地方」。当一个穷国拼命装出一切欣欣向荣的样子时,这种「同时高端破烂」就出现了。所以你会看到一家超豪华的博物馆,有巨大的水晶吊灯和抛光大理石地板,但洗手间里水龙头不出水。或者一家装修高级的高档餐厅,里面却热得跟蒸笼一样,因为空调坏了。</p><p>我听说,有时候游客都准备好要进朝鲜开始行程了,却被告知行程神秘取消——真实的原因往往是,比如那天羊角岛饭店的水停了。</p><h2 id="-6" tabindex="-1">** <a class="header-anchor" href="#-6" aria-label="Permalink to &quot;**&quot;">​</a></h2><ol start="9"><li>朝鲜人到今天还整天挂在嘴上谈朝鲜战争。**</li></ol><p>朝鲜战争在韩国的日常生活里根本没什么存在感。战争 60 年前就结束了,韩国今天有别的事要操心,比如作为世界第 15 大经济体在国际上活得有存在感。</p><p>在朝鲜,战争是永恒的话题,而朝鲜人所了解的战争几乎全是赤裸裸的谎言。他们被灌输的大谎言是:战争是由当时占领着韩国的美国挑起的——美国突袭了毫无防备的北方,企图控制整个国家。他们被告知,金日成英勇地击退了美国人,美国人溃败而归,然后继续占领韩国直到今天。</p><p>当然,真实的故事是:金日成(不过是苏联扶植起来的傀儡领袖,因为他们知道能控制他)拽了斯大林的袖子好几年,不停问能不能在苏联支持下进攻南方,直到斯大林终于说了句「唉去他妈的行吧」,北方就动手了。诚然,美国当时在南方发挥着重要作用,但那时候他们更关注其他事情,被打了个措手不及。他们对北方的进攻的回应,是带着联合国部队加入南方一起作战。不管你怎么看待美国当时扮演的角色,他们绝对没有通过袭击和平的北方来发动战争。</p><p>但事实从来拦不住朝鲜政府。我看过的每一份报纸里都有 <a href="https://waitbutwhy.com/wp-content/uploads/2013/09/NK-14.jpg" target="_blank" rel="noreferrer">像这样的东西</a>。</p><p>在朝鲜战争博物馆——那里被称作「美帝暴行博物馆」——我们的导游从头到尾都在告诉我们是美国人挑起了战争。房间里除了导游之外,所有人都知道真相。</p><h2 id="-7" tabindex="-1">** <a class="header-anchor" href="#-7" aria-label="Permalink to &quot;**&quot;">​</a></h2><ol start="10"><li>所有孩子无时无刻都穿着同样的制服,连不在学校时也穿。**</li></ol><h2 id="-8" tabindex="-1"><a href="https://1.bp.blogspot.com/-7YHczM2rx6Y/UoAY8QriFfI/AAAAAAAAGN8/B8VJ_gIDnZg/s320/IMG_0688.jpg" target="_blank" rel="noreferrer"><img src="'+y+'" alt=""></a> <a class="header-anchor" href="#-8" aria-label="Permalink to &quot;[![](/images/20-things-i-learned-while-i-was-in/IMG_0688.jpg)](https://1.bp.blogspot.com/-7YHczM2rx6Y/UoAY8QriFfI/AAAAAAAAGN8/B8VJ_gIDnZg/s320/IMG_0688.jpg)&quot;">​</a></h2><p><a href="https://1.bp.blogspot.com/-J--P57RfiO8/UoAY9dpHKtI/AAAAAAAAGOM/_bMNhXFTl-A/s400/IMG_2060.jpg" target="_blank" rel="noreferrer"><img src="'+q+'" alt=""></a></p><p>其实不是所有孩子——而是最富裕家庭的孩子。但这些恰恰是他们允许外国访客接触到的家庭,所以在我眼里就是这个样子。</p><h2 id="-9" tabindex="-1">** <a class="header-anchor" href="#-9" aria-label="Permalink to &quot;**&quot;">​</a></h2><ol start="11"><li>平壤市中心那座巨大的火箭酒店,最好别提。**</li></ol><p><a href="https://4.bp.blogspot.com/-rsYWFrdc_4Q/UoAY8RJmdTI/AAAAAAAAGOA/LPCZNM3t5CU/s640/IMG_0540.jpg" target="_blank" rel="noreferrer"><img src="'+I+'" alt=""></a></p><p>这座 105 层的柳京饭店 (Ryugyong Hotel),1987 年动工,到现在还没完工。对于一个经济停滞、基础设施腐朽、夜里看起来像 <a href="https://www.nasa.gov/content/korean-peninsula-seen-from-space-station" target="_blank" rel="noreferrer">这样</a> 的国家来说,搞这么个工程似乎有点奇怪。</p><p>但我们这是在朝鲜,所以为什么他妈的不行呢。</p><p>从照片里很难体会到这栋建筑立在平壤市中心有多诡异——这座城市其他的建筑都是苏联时代留下的破旧矮小混凝土楼房。下面这张图展示了柳京饭店前面的一栋典型平壤建筑——</p><p><a href="https://4.bp.blogspot.com/-NlTnH7x5CD0/UoAY8v-d9OI/AAAAAAAAGOI/wSRELrdVLjw/s640/IMG_0839.jpg" target="_blank" rel="noreferrer"><img src="'+P+'" alt=""></a></p><h2 id="_12-朝鲜人似乎对存放金日成和金正日遗体的陵墓完全没有幽默感。" tabindex="-1"><strong>12) 朝鲜人似乎对存放金日成和金正日遗体的陵墓完全没有幽默感。</strong> <a class="header-anchor" href="#_12-朝鲜人似乎对存放金日成和金正日遗体的陵墓完全没有幽默感。" aria-label="Permalink to &quot;**12) 朝鲜人似乎对存放金日成和金正日遗体的陵墓完全没有幽默感。**&quot;">​</a></h2><p>来看看我们的老朋友金正日最近在忙啥——</p><p><a href="https://3.bp.blogspot.com/-rK-L1CBGXEw/UkVzCmq5QiI/AAAAAAAAAFs/BNW-chtP08I/s640/170387569.jpg" target="_blank" rel="noreferrer"><img src="'+x+'" alt=""></a></p><p>这是本文里唯一一张不是我拍的照片——在陵墓里,也就是锦绣山太阳宫 (Kumsusan Palace of the Sun) 里,相机是<em>严格</em>禁止的。专家估计这座陵墓的建造成本在 1 亿到 9 亿美元之间。</p><p>整趟旅行有很多紧张时刻,而我在这里度过的时间是最紧张的。我们必须排成一列走进走出,还得对两位兄弟每人鞠三次躬。</p><h2 id="_13-朝鲜连交通女警都能搞得独裁范儿十足。" tabindex="-1"><strong>13) 朝鲜连交通女警都能搞得独裁范儿十足。</strong> <a class="header-anchor" href="#_13-朝鲜连交通女警都能搞得独裁范儿十足。" aria-label="Permalink to &quot;**13) 朝鲜连交通女警都能搞得独裁范儿十足。**&quot;">​</a></h2><p>看得人有点入迷。</p><h2 id="-10" tabindex="-1">** <a class="header-anchor" href="#-10" aria-label="Permalink to &quot;**&quot;">​</a></h2><ol start="14"><li>阿里郎表演 (Mass Games) 既震撼又让人不安。**</li></ol><p>先说震撼。看阿里郎表演的感觉就像参加奥运会开幕式。演出动用了 10 万 (!) 名表演者,其中很多是小孩子,用来展现朝鲜光辉的历史和欣欣向荣的现代化。背景是一幅由 2 万个孩子举着大型彩色卡片组成的惊人挂毯 (他们每人有一本卡片册,可以迅速翻页换色)。「壮丽」这个词我平时不太用,但这场表演真的壮丽。阿里郎表演每年夏天进行三个月,每周演出四天。</p><p>至于让人不安的部分,你只要说一句「朝鲜是世界上最贫穷的国家之一,几百万人在挨饿,医院基本瘫痪,几乎没有电力供应」,然后再回头读一遍上面那段。</p><p>不管怎么说,阿里郎是最典型的朝鲜活动——以宣传为核心,强调集体高于个人,而且考虑到国家目前的状况,把它当成头等大事完全说不通。</p><p>你可以在<a href="https://www.facebook.com/media/set/?set=a.551086294940276.1073741829.480646095317630&amp;type=1" target="_blank" rel="noreferrer">这里</a>看到照片,下面是我拍的一段视频,展示了演出片段:</p><h2 id="-11" tabindex="-1"><a class="header-anchor" href="#-11" aria-label="Permalink to &quot;&quot;">​</a></h2><p><strong>15) 朝鲜老百姓无法使用互联网,因为政府担心人民看到某些内容后会对西方产生不公正的负面看法,而政府希望通过禁止人民上网来保护西方的名誉。</strong></p><p>是的。当我问我们的朝鲜导游为什么没人能上互联网时,他给我讲的就是<em>这个</em>故事。这是我听过最荒谬的解释之一——显然连政府都懒得编个像样的谎话了。</p><p>(最有特权的)人们<em>能</em>用的,是朝鲜的内部局域网,一个仅限于政府批准的朝鲜网站的网络。</p><p>自然而然地,朝鲜在<a href="https://en.wikipedia.org/wiki/Press_Freedom_Index#Rankings_and_scores_by_country" target="_blank" rel="noreferrer">新闻自由指数 (Press Freedom Index)</a>中排名倒数第二,只赢了厄立特里亚 (干得漂亮,厄立特里亚)。</p><h2 id="-12" tabindex="-1">** <a class="header-anchor" href="#-12" aria-label="Permalink to &quot;**&quot;">​</a></h2><ol start="16"><li>金正日用 MacBook Pro。**</li></ol><p><a href="https://2.bp.blogspot.com/-LsHQlXLqEpI/UoAY1P2NMmI/AAAAAAAAGNs/SeTmfK83ryg/s640/Finder.png" target="_blank" rel="noreferrer"><img src="'+j+'" alt=""></a></p><p>我亲眼看见的。在参观完陈列在陵墓里的他的遗体之后,他们把我们带到楼下的金正日博物馆,里面陈列着他一生获得的奖项和荣誉、一张巨大的动画地图显示他一生走过的每一条路线,还有他出行时用过几百次的那列火车 (他怕坐飞机)。</p><p>他们让我们看了车厢内部,包括他 (据说) 去世的那间房。房间里有一套他<a href="http://www.dailymail.co.uk/news/article-1264289/Kim-Jong-Il-global-fashion-icon-thanks-trademark-zip-suit.html" target="_blank" rel="noreferrer">最爱的衣服</a>的替换装,桌上摆着一台 MacBook Pro。</p><p>想象金正日把东西拖进 Dock、最小化窗口、打开 Finder 的画面挺诡异的,但事实就是这样。</p><h2 id="-13" tabindex="-1">** <a class="header-anchor" href="#-13" aria-label="Permalink to &quot;**&quot;">​</a></h2><ol start="17"><li>我发誓,大多数时候人们一起走路时是踏着同一个步子的。**</li></ol><p>拜托看看——</p><h2 id="_18-朝鲜是那种-古代博物馆听起来像美好旧时光-的唯一地方。" tabindex="-1"><strong>18) 朝鲜是那种&quot;古代博物馆听起来像美好旧时光&quot;的唯一地方。</strong> <a class="header-anchor" href="#_18-朝鲜是那种-古代博物馆听起来像美好旧时光-的唯一地方。" aria-label="Permalink to &quot;**18) 朝鲜是那种&quot;古代博物馆听起来像美好旧时光&quot;的唯一地方。**&quot;">​</a></h2><p>通常你去任何一个国家的古代博物馆,都会想:&quot;谢天谢地我没活在那时候。&quot;不管是墨西哥的活人挖心、欧洲的公开处决和黑死病,还是亚洲那些残酷的极权帝国,活在&quot;现在&quot;通常比活在&quot;过去&quot;好得多。</p><p>但在朝鲜,当我听导游一个接一个讲述统治半岛的古代王朝故事时,我脑子里一直在想:&quot;呃,好像还是比现在住这儿强。&quot;</p><h2 id="_19-这段视频里的眼泪显然是真的。" tabindex="-1"><strong>19) <a href="https://www.youtube.com/watch?v=tZsVP2WoE9E" target="_blank" rel="noreferrer">这段视频</a>里的眼泪显然是真的。</strong> <a class="header-anchor" href="#_19-这段视频里的眼泪显然是真的。" aria-label="Permalink to &quot;**19) [这段视频](https://www.youtube.com/watch?v=tZsVP2WoE9E)里的眼泪显然是真的。**&quot;">​</a></h2><p>好吧我不确定是不是全都真的,或者有些人是因为不哭就会被送去劳改营待一辈子才哭的。但我原本以为他们基本上都是在假装出<em>那种</em>程度的情绪,而下面这个故事推翻了我的这个假设:</p><p>我参加的那个旅行社的一位新西兰籍员工告诉我,金正日去世的消息传来时,他正在朝鲜<em>境外</em>和一名朝鲜政府旅游局的工作人员开会(你能在朝鲜境外见到朝鲜人的机会屈指可数)。他说当时那人正想用笔签个字,手抖得厉害到根本签不了。那人随即冲进另一个房间,几个小时后才出来,脸肿着,眼睛通红。这可是个身处朝鲜境外、没理由装出感情的人。</p><p>一个残暴无情的极权独裁者,得对他的人民玩<em>相当</em>高明的心理把戏,才能真正被爱戴——金家人干这个是行家。</p><h2 id="-14" tabindex="-1">** <a class="header-anchor" href="#-14" aria-label="Permalink to &quot;**&quot;">​</a></h2><ol start="20"><li>事实证明,世界上真的存在这样一个地方,它能让你在入境中国时忍不住感叹:「谢天谢地,终于回到这片自由的乐土!」**</li></ol><p><a href="https://waitbutwhy.com/" target="_blank" rel="noreferrer"><img src="'+N+'" alt=""></a></p><p>朝鲜。一个和任何地方都不一样的地方。</p><p>————————-</p><p><strong>这次旅行的照片在<a href="https://www.facebook.com/media/set/?set=a.551086294940276.1073741829.480646095317630&amp;type=1" target="_blank" rel="noreferrer">这里</a>。</strong></p><p>下面是我在平壤的万景台学生少年宫拍的一些视频。这是一所专门招收具有精英级艺术天赋孩子的学校。当然,只有出身最高级别家庭的孩子才有机会进入这所学校。(是的,我现在知道竖屏视频是件坏事,不是好事。)</p><p>首先我们有机会看到孩子们在练习:</p><p><a href="https://www.youtube.com/watch?v=tG1Fo7LP2zU" target="_blank" rel="noreferrer">小女孩们在练习跳舞。</a><br><a href="https://www.youtube.com/watch?v=Kl76owSux-E" target="_blank" rel="noreferrer">小女孩们在练习一种奇怪的乐器,听起来很棒。</a><br><a href="https://www.youtube.com/watch?v=wr34Wxv6U8E" target="_blank" rel="noreferrer">小孩们在练习手风琴。</a><br><a href="https://www.youtube.com/watch?v=XG8y-Lklats" target="_blank" rel="noreferrer">一个非常专注的小女孩在练习刺绣。</a></p><p>然后我们看了一场精彩的演出(请原谅糟糕的视频质量):</p><p><a href="https://www.youtube.com/watch?v=Fb-RblpI2Sk" target="_blank" rel="noreferrer">开场节目。</a><br><a href="https://www.youtube.com/watch?v=gaoGFeFrd5Y" target="_blank" rel="noreferrer">四个穿红靴子的小女孩跳的一段<em>愉快</em>的舞蹈。</a><br><a href="https://www.youtube.com/watch?v=spqUr0soSro" target="_blank" rel="noreferrer">一个把木琴和鼓打得出神入化的小女孩。</a><br><a href="https://www.youtube.com/watch?v=SkLTv2BXH_A" target="_blank" rel="noreferrer">一个把尤克里里弹得出神入化的小男孩。</a><br><a href="https://www.youtube.com/watch?v=iG-hWbT0GDA" target="_blank" rel="noreferrer">一个活泼的小女孩跳的一支优雅舞蹈。</a><br><a href="https://www.youtube.com/watch?v=v67y0zNxw7g" target="_blank" rel="noreferrer">一个用套索让我惊掉下巴的小男孩。</a><br><a href="https://www.youtube.com/watch?v=dpvhiaNV2iA" target="_blank" rel="noreferrer">一群女孩拿着扇子跳舞。</a></p><p>我走出去的时候,向观众席上的孩子们挥了挥手,<a href="https://www.youtube.com/watch?v=enYm68BmSNg" target="_blank" rel="noreferrer">这是他们向我挥手回应的样子</a>。</p><p>探访这些孩子是整趟旅程最让人难过的部分。他们和其他任何孩子一样值得拥有美好的生活,而他们却被困在这么一个烂透了的地方,真的挺让人心碎的。整个国家的人民都值得更好的生活——希望那里能尽快有所改变。</p><p>查看所有视频请点<a href="https://www.youtube.com/channel/UCO7b5EvPM9UJLDaO_OXCQrg" target="_blank" rel="noreferrer">这里</a>。</p><h2 id="好了拜拜。" tabindex="-1"><a href="https://www.youtube.com/watch?v=FN0G7MlDDjw&amp;feature=youtu.be" target="_blank" rel="noreferrer">好了拜拜。</a> <a class="header-anchor" href="#好了拜拜。" aria-label="Permalink to &quot;[好了拜拜。](https://www.youtube.com/watch?v=FN0G7MlDDjw&amp;feature=youtu.be)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会发送给你。</p><h2 id="想支持-wait-but-why-请访问我们的-patreon-页面。" tabindex="-1">想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。 <a class="header-anchor" href="#想支持-wait-but-why-请访问我们的-patreon-页面。" aria-label="Permalink to &quot;想支持 Wait But Why,请访问我们的 **[Patreon 页面](https://patreon.com/waitbutwhy)**。&quot;">​</a></h2><p><strong>相关 Wait But Why 文章</strong></p><p><a href="https://waitbutwhy.com/2014/09/muhammad-isis-iraqs-full-story.html" target="_blank" rel="noreferrer">从穆罕默德到 ISIS:伊拉克的完整故事</a><br><a href="https://waitbutwhy.com/2014/08/19-things-learned-nigeria.html" target="_blank" rel="noreferrer">我在尼日利亚学到的 19 件事</a><br><a href="https://waitbutwhy.com/2014/09/but-what-about-greenland.html" target="_blank" rel="noreferrer">那格陵兰呢?</a></p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2013/09/20-things-i-learned-while-i-was-in.html&amp;description=20%20Things%20I%20Learned%20While%20I%20Was%20in%20North%20Korea" target="_blank" rel="noreferrer"><img src="'+M+'" alt=""></a></p>',151)])])}const Y=a(K,[["render",v]]);export{B as __pageData,Y as default};
